  function propertyHubCard(p){const ids=ownerPropIds(),checked=ids.includes(p.id),cleaners=propCleaners(p.id);const cleanerText=cleaners.length?cleaners.map(x=>`<span class='badge green'>${esc(cleanerLabel(x.cleaner_code))}</span>`).join(''):`<span class='property-meta-line'>保洁：未绑定</span>`;return `<div class='property-card-row property-hub-card'><div><label style='display:flex;gap:10px;align-items:center;flex-wrap:wrap'><input type='checkbox' value='${esc(p.id)}'${checked?' checked':''} onchange='setOwnerPropertyFilter("${esc(p.id)}",this.checked)'><span class='property-title-line'>${esc(displayPropertyName(p.name,p.id))}</span></label><div class='property-meta-line'>${propRooms(p.id).length} 个房间 · ${propAreas(p.id).length} 个公区 · ${cleaners.length} 个保洁绑定</div><div>${cleanerText}</div></div><div class='property-card-actions'><button class='smallbtn' onclick='editPropertyName("${esc(p.id)}",this)'>修改名字</button><button class='smallbtn primary' onclick='openPropertyRooms("${esc(p.id)}")'>进入房间管理</button><button class='smallbtn' onclick='deletePropertyUi("${esc(p.id)}",this)'>删除房源</button></div></div>`;}
  function ownerScopeHtml(){const ids=ownerPropIds(),label=!ids.length?'未选择房源':ownerScopeAll()?'全部房源':ids.length===1?propName(ids[0]):`${ids.length} 个房源`;const cards=props().map(propertyHubCard).join('');return `<div class="metric property-scope-panel" style="grid-column:1/-1"><div class="property-scope-head"><div><div class="small">房源筛选 / 房源管理</div><strong>${esc(label)}</strong><div class="small">勾选控制下面所有菜单显示哪些房源；也可以在这里添加、改名、删除房源，或进入单个房源的房间管理。</div></div><div class="property-scope-actions"><button class="smallbtn primary" onclick="addProperty()">添加房源</button><button class="smallbtn" onclick="toggleOwnerPropertySelection()">全选/反选</button><button class="smallbtn" onclick="clearOwnerPropertyFilter()">清空</button></div></div><div id="ownerPropertyFilter" class="property-cards">${cards||'<span class="small">还没有房源，先点右上角添加房源。</span>'}</div></div>`;}
  function allOwnerNotes(){return ownerCleanNotes().map(n=>({...n,kind:'cleaning'})).concat(ownerRoomDateNotes().map(n=>({date:n.date,target_id:n.room_id,target_type:'room',note:n.note,priority:n.priority,created_by:n.created_by,kind:'roomDate'})));}
